import socket, ssl, base64, os, hashlib, struct, json, re, sys, time, random
from urllib.parse import urlparse

class WS:
    def __init__(self, url):
        u=urlparse(url)
        self.host=u.hostname
        self.port=u.port or (443 if u.scheme=='wss' else 80)
        self.path=u.path or '/'
        raw=socket.create_connection((self.host,self.port),timeout=10)
        if u.scheme=='wss':
            ctx=ssl.create_default_context()
            raw=ctx.wrap_socket(raw,server_hostname=self.host)
        self.s=raw
        key=base64.b64encode(os.urandom(16)).decode()
        req=(f"GET {self.path} HTTP/1.1\r\nHost: {self.host}:{self.port}\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Key: {key}\r\nSec-WebSocket-Version: 13\r\nOrigin: http://{self.host}:{self.port}\r\n\r\n")
        self.s.sendall(req.encode())
        resp=b''
        while b'\r\n\r\n' not in resp:
            resp+=self.s.recv(4096)
        if b' 101 ' not in resp.split(b'\r\n',1)[0]:
            raise Exception('handshake failed: '+resp.decode(errors='ignore'))
    def send(self, data):
        if isinstance(data,str): data=data.encode()
        b1=0x81
        mask_bit=0x80
        n=len(data)
        if n<126:
            hdr=struct.pack('!BB',b1,mask_bit|n)
        elif n<65536:
            hdr=struct.pack('!BBH',b1,mask_bit|126,n)
        else:
            hdr=struct.pack('!BBQ',b1,mask_bit|127,n)
        mask=os.urandom(4)
        masked=bytes(data[i]^mask[i%4] for i in range(n))
        self.s.sendall(hdr+mask+masked)
    def recv(self, timeout=10):
        self.s.settimeout(timeout)
        while True:
            h=self.s.recv(2)
            if not h: return None
            b1,b2=h
            opcode=b1&0xf
            masked=b2>>7
            n=b2&0x7f
            if n==126:
                n=struct.unpack('!H',self.s.recv(2))[0]
            elif n==127:
                n=struct.unpack('!Q',self.s.recv(8))[0]
            mask=self.s.recv(4) if masked else b''
            data=b''
            while len(data)<n:
                data+=self.s.recv(n-len(data))
            if masked:
                data=bytes(data[i]^mask[i%4] for i in range(n))
            if opcode==0x9:
                self.send_pong(data); continue
            if opcode==0xA:
                continue
            if opcode==0x8:
                return None
            return data.decode(errors='ignore')
    def send_pong(self,data=b''):
        if isinstance(data,str): data=data.encode()
        b1=0x8A; mask_bit=0x80; n=len(data)
        if n<126: hdr=struct.pack('!BB',b1,mask_bit|n)
        elif n<65536: hdr=struct.pack('!BBH',b1,mask_bit|126,n)
        else: hdr=struct.pack('!BBQ',b1,mask_bit|127,n)
        mask=os.urandom(4)
        masked=bytes(data[i]^mask[i%4] for i in range(n))
        self.s.sendall(hdr+mask+masked)

def ddp_connect(url):
    ws=WS(url)
    ws.send(json.dumps({"msg":"connect","version":"1","support":["1","pre2","pre1"]}))
    print('RECV',ws.recv())
    return ws

if __name__=='__main__':
    ws=ddp_connect(sys.argv[1] if len(sys.argv)>1 else 'ws://web.chal.csaw.io:5000/websocket')
    while True:
        line=sys.stdin.readline()
        if not line: break
        ws.send(line.strip())
        t=time.time()+2
        while time.time()<t:
            try:
                m=ws.recv(timeout=0.5)
            except Exception:
                break
            if not m: break
            print('RECV',m)

